        homeLongitude: homeLongitude ?? null,
        homeState: homeState ?? null,
      })
    }
  },

  clear: () => {
    set({
      homeLatitude: null,
      homeLongitude: null,
      homeState: null,
      loaded: false,
      loading: false,
    })
  },
}))

