import { useEffect, useMemo, useState, useCallback } from 'react'
import { useSearchParams } from 'react-router-dom'
import { graphql } from 'gql.tada'
import { useQuery } from '@/lib/graphql'
import { usePreferencesStore } from '@/stores/preferencesStore'
import {
  Box,
  Collapse,
  Container,
  Flex,
  Group,
  NativeSelect,
  Pagination,
  SimpleGrid,
  Stack,
  Text,
  Title,
} from '@mantine/core'
import { Button } from '@/components/ui/button'
import { useDisclosure, useMediaQuery } from '@mantine/hooks'
import { Download, FileDown, SlidersHorizontal } from 'lucide-react'
import {
  type SearchField,
  type SearchInstitution,
  type SearchOutputField,
  type UserLocationValue,
  type ViewMode,
  fieldsByTheme,
  buildFilterInputs,
  serializeFilterValue,
  parseUrlToFilters,
  parseBlendParam,
  serializeBlendWeights,
  FilterControl,
  LocationInput,
  InstitutionDetail,
  InstitutionCard,
  InstitutionCardSkeleton,
  ResultsList,
  ResultsMap,
  ResultsTable,
  ColumnPicker,
  ViewToggle,
  SortControl,
  downloadSearchPdf,
  RankingBlendBuilder,
  ActiveFilterPills,
  type SortState,
} from '@/components/search'
import { useDataSources } from '@/components/search/useDataSources'

// ── Constants ────────────────────────────────────────────────────────────────

const MAX_RESULTS = 100
const PAGE_SIZE_OPTIONS = [5, 10, 20, 50, 100]
const DEFAULT_PAGE_SIZE = 20
const VISIBLE_COLUMNS_KEY = 'kapow:visible-columns'
const COLUMN_ORDER_KEY = 'kapow:column-order'
const VIEW_MODE_KEY = 'kapow:results-view'
const VALID_VIEW_MODES: ViewMode[] = ['card', 'list', 'table', 'map']

// ── GraphQL queries ────────────────────────────────────────────────────────────

const SearchFieldsQuery = graphql(`
  query SearchFields {
    searchFields {
      __typename
      name
      label
      description
      theme
      visibility
      searchability
      exportable
      dataSourceID
      ... on ChoiceSearchField {
        options {
          value
          displayName
        }
        minSelections
        maxSelections
      }
      ... on NumericalSearchField {
        min
        max
        step
        unit
        defaultValue
      }
      ... on NumericalRangeSearchField {
        min
        max
        step
        unit
        defaultLower
        defaultUpper
      }
      ... on GeoSearchField {
        defaultLatitude
        defaultLongitude
        maxRadiusMiles
      }
    }
  }
`)

const SearchOutputFieldsQuery = graphql(`
  query SearchOutputFields {
    searchOutputFields {
      name
      label
      theme
      defaultVisible
      exportable
      dataSourceID
      sortable
      unit
      outputKey
    }
  }
`)

const SearchQuery = graphql(`
  query Search($filters: [FilterInput!], $limit: Int, $offset: Int, $sort: SortInput, $userLocation: UserLocation, $rankingBlend: [RankingBlendWeight!]) {
    search(filters: $filters, limit: $limit, offset: $offset, sort: $sort, userLocation: $userLocation, rankingBlend: $rankingBlend) {
      results {
        unitID
        name
        city
        state
        latitude
        longitude
        distance
        myPrice
        blendScore
        locationDetails {
          locale
          region
          metroArea
          metroDistance
        }
        academics {
          institutionType
          highestDegree
          enrollment
          gradEnrollment
          studentFacultyRatio
          fullTimeFacultyRate
          gender
          onlineOnly
          carnegieBasic
          carnegieSizeSetting
        }
        cost {
          avgNetPrice
          tuitionInState
          tuitionOutOfState
          roomAndBoard
          avgNetPriceLowIncome
          pellGrantRate
          federalLoanRate
          endowment
        }
