    theme: 'LOCATION',
    visibility: 'VISIBLE',
    searchability: 'NOT_SEARCHABLE',
    exportable: true,
  },
]

const MOCK_SEARCH_DATA = {
  search: {
    results: [
      { unitID: '166683', name: 'MIT', city: 'Cambridge', state: 'MA' },
      { unitID: '130794', name: 'Harvard University', city: 'Cambridge', state: 'MA' },
    ],
    total: 2,
    limit: 20,
    offset: 0,
  },
}

// ── Mock setup ─────────────────────────────────────────────────────────────────

function setupMocks(
  fieldsOverride?: Record<string, unknown>,
  searchOverride?: Record<string, unknown>,
) {
  const fieldsState = {
    fetching: false,
    data: { searchFields: MOCK_FIELDS },
    error: undefined,
    ...fieldsOverride,
  }
  const searchState = {
    fetching: false,
    data: MOCK_SEARCH_DATA,
    error: undefined,
    ...searchOverride,
  }
  const outputFieldsState = {
    fetching: false,
    data: { searchOutputFields: MOCK_OUTPUT_FIELDS },
    error: undefined,
  }
  const detailState = {
    fetching: false,
    data: { institution: null },
    error: undefined,
  }
  const dataSourcesState = {
    fetching: false,
    data: { dataSources: [] },
    error: undefined,
  }
  mockUseQuery.mockImplementation((args: { query: unknown }) => {
    const opName = getOperationName(args.query)
    if (opName === 'SearchFields') {
      return [fieldsState, vi.fn()]
    }
    if (opName === 'SearchOutputFields') {
      return [outputFieldsState, vi.fn()]
    }
    if (opName === 'InstitutionDetail') {
      return [detailState, vi.fn()]
    }
    if (opName === 'DataSources') {
      return [dataSourcesState, vi.fn()]
    }
    return [searchState, vi.fn()]
  })
}

function renderSearch(initialEntry = '/search') {
  return render(
    <MemoryRouter initialEntries={[initialEntry]}>
      <AppProviders>
        <Search />
      </AppProviders>
    </MemoryRouter>,
  )
}

// ── Tests ──────────────────────────────────────────────────────────────────────

describe('Search', () => {
  beforeEach(() => {
    mockUseQuery.mockReset()
    localStorage.clear()
    mockPrefsState.homeLatitude = null
    mockPrefsState.homeLongitude = null
    mockPrefsState.homeState = null
    mockPrefsState.loaded = false
    setupMocks()
  })

  afterEach(() => {
    vi.useRealTimers()
  })

  it('renders the filter sidebar and results heading', () => {
    renderSearch()
    expect(screen.getByText(/filters/i)).toBeInTheDocument()
    expect(screen.getByRole('heading', { name: /results/i })).toBeInTheDocument()
  })

  it('shows a loading indicator while field metadata is fetching', () => {
    setupMocks({ fetching: true, data: undefined })
    renderSearch()
    expect(screen.getByText(/loading filters/i)).toBeInTheDocument()
  })

  it('shows an error message when field metadata fails to load', () => {
    setupMocks({ fetching: false, data: undefined, error: new Error('network error') })
    renderSearch()
    expect(screen.getByText(/failed to load filters/i)).toBeInTheDocument()
  })

  it('renders a text input for TextSearchField', () => {
    renderSearch()
    expect(screen.getByRole('textbox', { name: /institution name/i })).toBeInTheDocument()
  })

  it('renders a checkbox for BinarySearchField', () => {
    renderSearch()
    expect(screen.getByRole('checkbox', { name: /hbcu/i })).toBeInTheDocument()
  })

  it('renders geo filter inputs for GeoSearchField', () => {
    renderSearch()
    expect(screen.getByRole('spinbutton', { name: /location latitude/i })).toBeInTheDocument()
    expect(screen.getByRole('spinbutton', { name: /location longitude/i })).toBeInTheDocument()
  })

  it('renders a <select> for a ChoiceSearchField with maxSelections === 1', () => {
    renderSearch()
    const select = screen.getByRole('combobox', { name: /control/i })
    expect(select).toBeInTheDocument()
    expect(select.tagName).toBe('SELECT')
    // 3 options + the "Any" placeholder
    expect(select.querySelectorAll('option')).toHaveLength(4)
  })

  it('renders checkboxes for a ChoiceSearchField with maxSelections === null', () => {
    renderSearch()
    expect(screen.getByRole('checkbox', { name: /common app/i })).toBeInTheDocument()
    expect(screen.getByRole('checkbox', { name: /coalition/i })).toBeInTheDocument()
    expect(screen.getByRole('checkbox', { name: /apply texas/i })).toBeInTheDocument()
  })

  it('selecting a <select> option sets a SingleEnumFilter', async () => {
    const user = userEvent.setup()
    renderSearch()
    const select = screen.getByRole('combobox', { name: /control/i })
    await user.selectOptions(select, '1')
    expect(select).toHaveValue('1')
  })

  it('checking a multi-select checkbox sets a MultiEnumFilter', async () => {
    const user = userEvent.setup()
    renderSearch()
    const checkbox = screen.getByRole('checkbox', { name: /common app/i })
    await user.click(checkbox)
    expect(checkbox).toBeChecked()
  })

  it('unchecking a multi-select checkbox removes the value from the filter', async () => {
    const user = userEvent.setup()
    renderSearch()
    const checkbox = screen.getByRole('checkbox', { name: /common app/i })
    await user.click(checkbox)
    expect(checkbox).toBeChecked()
    await user.click(checkbox)
    expect(checkbox).not.toBeChecked()
  })

  it('does not render HIDDEN fields in the sidebar', () => {
    renderSearch()
    expect(screen.queryByText('Hidden Field')).not.toBeInTheDocument()
  })

  it('renders NOT_SEARCHABLE fields as display-only with no filter control', () => {
    renderSearch()
    // "City" appears in both the filter sidebar and table header
    expect(screen.getAllByText('City').length).toBeGreaterThan(0)
    expect(screen.getAllByText(/display only/i).length).toBeGreaterThan(0)
  })

  it('renders search results with institution name, city, and state', () => {
    renderSearch()
    expect(screen.getByText('MIT')).toBeInTheDocument()
    expect(screen.getByText('Harvard University')).toBeInTheDocument()
    // Default card view renders city, state together
    expect(screen.getAllByText('Cambridge, MA').length).toBeGreaterThan(0)
  })

  it('opens institution detail modal when clicking a result card', async () => {
    const user = userEvent.setup()
    renderSearch()
    await user.click(screen.getByText('MIT'))
    expect(screen.getByRole('dialog')).toBeInTheDocument()
  })

  it('shows loading skeletons while search is fetching', () => {
    setupMocks(undefined, { fetching: true, data: undefined })
    renderSearch()
    expect(screen.getByTestId('results-loading')).toBeInTheDocument()
    expect(screen.getAllByTestId('result-skeleton')).toHaveLength(3)
  })

  it('shows empty state with "Clear all filters" button when total is 0', () => {
    setupMocks(undefined, {
      data: { search: { results: [], total: 0, limit: 20, offset: 0 } },
    })
    renderSearch()
    expect(screen.getByText(/no colleges match your filters/i)).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /clear all filters/i })).toBeInTheDocument()
  })

  it('shows error state with retry button on search error', () => {
    setupMocks(undefined, { fetching: false, data: undefined, error: new Error('fail') })
    renderSearch()
    expect(screen.getByText(/something went wrong/i)).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /retry/i })).toBeInTheDocument()
  })

  it('shows "Showing X–Y of Z" result count text', () => {
    renderSearch()
    expect(screen.getByText(/showing 1–2 of 2 institutions found/i)).toBeInTheDocument()
  })

  it('accepts typed text in a TextSearchField input', async () => {
    const user = userEvent.setup()
    renderSearch()
    const input = screen.getByRole('textbox', { name: /institution name/i })
    await user.type(input, 'MIT')
    expect(input).toHaveValue('MIT')
  })

  it('pre-populates the name filter from the ?q= URL parameter', () => {
    renderSearch('/search?q=MIT')
    const input = screen.getByRole('textbox', { name: /institution name/i })
    expect(input).toHaveValue('MIT')
  })

  it('toggles a BinarySearchField checkbox', async () => {
    const user = userEvent.setup()
    renderSearch()
    const checkbox = screen.getByRole('checkbox', { name: /hbcu/i })
    expect(checkbox).not.toBeChecked()
    await user.click(checkbox)
    expect(checkbox).toBeChecked()
